SELECT a.*,
       f.file_pid,
       CASE WHEN f.file_id IS NULL OR f.del_flag = 1 THEN TRUE ELSE FALSE END AS file_deleted,
       CASE WHEN f.archived = 1 THEN TRUE ELSE FALSE END AS file_archived
FROM audit_log a
LEFT JOIN file_info f ON a.target_id = f.file_id


